svg.script:
const BASE = 'https://statevector-693279698669.us-central1.run.app';
const SECRET = 'sv:demo:cell';

const palette = ['#e74c3c','#3498db','#2ecc71','#f39c12','#9b59b6','#1abc9c','#e67e22','#f1c40f'];
const words = ['alive','thinking','ready','waiting','listening','dreaming','seeking','becoming'];
const radii = [80, 100, 120, 140, 100, 90, 110, 130];
let idx = 0;

const cell      = document.getElementById('cell');
const cellLabel  = document.getElementById('cellLabel');
const stateDisp  = document.getElementById('stateDisplay');
const tsDisp     = document.getElementById('tsDisplay');

function currentState() {
  return {
    color:   palette[idx % palette.length],
    radius:  radii[idx % radii.length],
    message: words[idx % words.length]
  };
}

function render(s) {
  cell.setAttribute('fill', s.color);
  cell.setAttribute('r', s.radius);
  cellLabel.textContent = s.message;
  stateDisp.textContent = JSON.stringify(s);
}

async function writeState() {
  const s = currentState();
  render(s);
  try {
    const r = await fetch(BASE + '/v', {
      method: 'PUT',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({ key: SECRET, val: s, ttl: 86400 })
    });
    const d = await r.json();
    tsDisp.textContent = new Date().toLocaleTimeString();
  } catch(e) {
    tsDisp.textContent = 'error: ' + e.message;
  }
}

// Load current state from server on init
async function loadState() {
  try {
    const hash = '3f0de3004fae209973c6ffea11d2da247b9799ad85a474b27f7307a642efb5f9';
    const r = await fetch(BASE + '/v/' + hash);
    if (r.ok) {
      const d = await r.json();
      const s = d.val;
      // Sync idx to current color
      const ci = palette.indexOf(s.color);
      if (ci >= 0) idx = ci;
      render(s);
      stateDisp.textContent = JSON.stringify(s);
      tsDisp.textContent = new Date(d.ts * 1000).toLocaleTimeString();
    }
  } catch(e) {}
}

loadState();

cell.addEventListener('click', function() {
  idx = (idx + 1) % palette.length;
  writeState();
});
